class IoTController:
    def __init__(self, pin=2, active_high=True):
        self.pin_no = pin
        self.active_high = active_high
        self.pin = machine.Pin(pin, machine.Pin.OUT)
        self.state = False
        self.turn_off()

    def turn_on(self):
        self.state = True
        self.pin.value(1 if self.active_high else 0)

    def turn_off(self):
        self.state = False
        self.pin.value(0 if self.active_high else 1)

    def toggle(self):
        if self.state:
            self.turn_off()
        else:
            self.turn_on()

    def status(self):
        return {"on": bool(self.state), "pin": self.pin_no}

